/* ═══════════════════════════════════════════════════════════════
   hk-data.js — Hidden Keys · Source de données globale
   Version avec chemins images (plus de base64 inline)
   Dossier : hk-data/  — toutes les pages chargent ce fichier
   Usage   : <script src="hk-data/hk-data.js"></script>
   ═══════════════════════════════════════════════════════════════

   PHOTOS dans hk-data/ :
     villa-1br.jpg       Villa 1 chambre  (Bulan / Studio)
     villa-2br.jpg       Villa 2 chambres (Indah / Serenity)
     villa-2br-b.jpg     Villa 2 chambres variante
     villa-3br.jpg       Villa 3 chambres (Karma)
     villa-5br.jpg       Villa 5 chambres (Surya)
     hotel.jpg           Photo principale hôtel
     bungalow.jpg        Chambre bungalow (x8, toutes identiques)
     jean-loup.jpg       Avatar owner Jean-Loup
     manager-kadej.jpg   Manager Kadej
     agent-loana.jpg     Agent Loana
     agent-jimmy.jpg     Agent Jimmy
     agent-jack.jpg      Agent Jack
     agent-renardo.jpg   Agent Renardo
     agent-isabella.jpg  Agent Isabella
     agent-lulu.jpg      Agent Lulu
   ═══════════════════════════════════════════════════════════════ */

/* ── Helper : résoudre le chemin relatif depuis n'importe quelle page ── */
/* hk-data.js est dans le même dossier que les pages HTML */
window.HK_BASE = '';

function hkImg(filename){
  /* Chemin relatif depuis les pages HTML (un niveau au-dessus du dossier) */
  return '' + filename;
}

/* ── Chemins images ── */
